  );
}

export function Await<Resolve>({
  children,
  errorElement,
  resolve,
}: AwaitProps<Resolve>) {
  let dataRouterContext = React.useContext(DataRouterContext);
  let dataRouterStateContext = React.useContext(DataRouterStateContext);

  let onError = React.useCallback(
    (error: unknown, errorInfo?: React.ErrorInfo) => {
      if (
        dataRouterContext &&
        dataRouterContext.onError &&
        dataRouterStateContext
      ) {
        dataRouterContext.onError(error, {
          location: dataRouterStateContext.location,
          params: dataRouterStateContext.matches[0]?.params || {},
          pattern: getRoutePattern(dataRouterStateContext.matches),
          errorInfo,
        });
      }
    },
    [dataRouterContext, dataRouterStateContext],
  );

  return (
    <AwaitErrorBoundary
      resolve={resolve}
      errorElement={errorElement}
      onError={onError}
    >
      <ResolveAwait>{children}</ResolveAwait>
    </AwaitErrorBoundary>
  );
}

function ListBoxSectionInner<T>(
  props: ListBoxSectionProps<T>,
  ref: ForwardedRef<HTMLElement>,
  section: Node<T>,
  className = 'react-aria-ListBoxSection'
) {
  let state = useContext(ListStateContext)!;
  let {dragAndDropHooks, dropState} = useContext(DragAndDropContext)!;
  let {CollectionBranch} = useContext(CollectionRendererContext);
  let [headingRef, heading] = useSlot();
  let {headingProps, groupProps} = useListBoxSection({
    heading,
    'aria-label': props['aria-label'] ?? undefined
  });
  let renderProps = useRenderProps({
    ...props,
    id: undefined,
    children: undefined,
    defaultClassName: className,
    values: undefined
  });

  let DOMProps = filterDOMProps(props as any, {global: true});
  delete DOMProps.id;

  return (
    <dom.section {...mergeProps(DOMProps, renderProps, groupProps)} ref={ref}>
      <HeaderContext.Provider value={{...headingProps, ref: headingRef}}>
        <CollectionBranch
          collection={state.collection}
          parent={section}
          renderDropIndicator={useRenderDropIndicator(dragAndDropHooks, dropState)}
        />
      </HeaderContext.Provider>
    </dom.section>
  );
}

function RootDropIndicator() {
  let state = useContext(TableStateContext)!;
  let {dragAndDropHooks, dropState} = useContext(DragAndDropContext);
  let ref = useRef<HTMLDivElement>(null);
  let {dropIndicatorProps} = dragAndDropHooks!.useDropIndicator!(
    {
      target: {type: 'root'}
    },
    dropState!,
    ref
  );
  let isDropTarget = dropState!.isDropTarget({type: 'root'});
  let {visuallyHiddenProps} = useVisuallyHidden();

  if (!isDropTarget && dropIndicatorProps['aria-hidden']) {
    return null;
  }

  return (
    <TableRowElementType
      role="row"
      aria-hidden={dropIndicatorProps['aria-hidden']}
      style={{height: 0}}>
      <TableCellElementType
        role="gridcell"
        colSpan={state.collection.columnCount}
        style={{padding: 0}}>
        <div role="button" {...visuallyHiddenProps} {...dropIndicatorProps} ref={ref} />
      </TableCellElementType>
    </TableRowElementType>
  );
}

(props, ref) => {
  const { children, placeholder, separator = ', ', ...localProps } = props
  const datePicker = useDatePickerContext()

  const hasValue = datePicker.value.length > 0

  if (typeof children === 'function') {
    return (
      <Fragment>
        {hasValue
          ? datePicker.value.map((value, index) => (
              <Fragment key={index}>
                {children({
                  value,
                  index,
                  valueAsString: datePicker.valueAsString[index],
                  remove: () => {
                    datePicker.setValue(datePicker.value.filter((_, i) => i !== index))
                  },
                })}
              </Fragment>
            ))
          : placeholder}
      </Fragment>
    )
  }

  return (
    <ark.span {...datePickerAnatomy.build().valueText.attrs} {...localProps} ref={ref}>
      {hasValue ? datePicker.valueAsString.join(separator) : placeholder}
    </ark.span>
  )
}

