  const activeItemClasses = clsx(styles['anchor-item--active'], testUtilsStyles['anchor-item--active']);

  return (
    <li data-itemid={`anchor-item-${index + 1}`} className={clsx(styles['anchor-item'], isActive && activeItemClasses)}>
      <a
        onClick={onClick}
        className={clsx(
          styles['anchor-link'],
          testUtilsStyles['anchor-link'],
          isActive && styles['anchor-link--active']
        )}
        {...(isActive ? { 'aria-current': true } : {})}
        href={anchor.href}
      >
        <span
          className={clsx(styles['anchor-link-text'], testUtilsStyles['anchor-link-text'])}
          style={{ paddingInlineStart: `${anchor.level * 16 + 2}px` }}
        >
          {anchor.text}
        </span>
        {anchor.info && (
          <span className={clsx(styles['anchor-link-info'], testUtilsStyles['anchor-link-info'])}>{anchor.info}</span>
        )}
      </a>
      {children}
    </li>
  );
}

(
  runtimeConfig: RuntimeDrawerConfig
): AppLayoutProps.Drawer & {
  orderPriority?: number;
  onToggle?: NonCancelableEventHandler<DrawerStateChangeParams>;
  headerActions?: ReadonlyArray<ButtonGroupProps.Item>;
} => {
  const { mountContent, unmountContent, trigger, ...runtimeDrawer } = runtimeConfig;

  return {
    ...runtimeDrawer,
    ariaLabels: { drawerName: runtimeDrawer.ariaLabels.content ?? '', ...runtimeDrawer.ariaLabels },
    trigger: trigger
      ? {
          ...(trigger.iconSvg && {
            iconSvg: convertRuntimeTriggerToReactNode(trigger.iconSvg),
          }),
        }
      : undefined,
    content: (
      <RuntimeDrawerWrapper
        key={runtimeDrawer.id}
        mountContent={mountContent}
        unmountContent={unmountContent}
        id={runtimeDrawer.id}
      />
    ),
    onResize: event => {
      fireNonCancelableEvent(runtimeDrawer.onResize, { size: event.detail.size, id: runtimeDrawer.id });
    },
    headerActions: runtimeDrawer.headerActions
      ? mapRuntimeHeaderActionsToHeaderActions(runtimeDrawer.headerActions)
      : undefined,
  };
}

private resolveChildLocation(p: HTMLElement, child: ChildNode, offsetInChild: number): DOMLocation {
  if (isTextNode(child)) {
    return { node: child, offset: offsetInChild };
  }

  if (!isHTMLElement(child)) {
    return { node: p, offset: Array.from(p.childNodes).indexOf(child) };
  }

  const tokenType = getTokenType(child);
  const childIndex = Array.from(p.childNodes).indexOf(child);

  if (tokenType === ElementType.Trigger) {
    if (offsetInChild === 0) {
      return { node: p, offset: childIndex };
    }
    const triggerTextNode = child.childNodes[0];
    if (triggerTextNode && isTextNode(triggerTextNode)) {
      return { node: triggerTextNode, offset: offsetInChild };
    }
    return { node: p, offset: childIndex };
  }

  if (isReferenceElementType(tokenType)) {
    if (offsetInChild === 0) {
      return { node: p, offset: childIndex };
    }
    const nextSibling = child.nextSibling;
    if (nextSibling) {
      return isTextNode(nextSibling) ? { node: nextSibling, offset: 0 } : { node: p, offset: childIndex + 1 };
    }
    return { node: p, offset: p.childNodes.length };
  }

  return { node: p, offset: childIndex };
}

function transformDrawerContent(j: any, path: any, addFullHeight: boolean) {
  const attrs = path.node.openingElement.attributes || []
  const children = path.node.children || []

  // Add height="100%" if needed
  const finalAttrs = addFullHeight
    ? [
        ...attrs,
        j.jsxAttribute(j.jsxIdentifier("height"), j.stringLiteral("100%")),
      ]
    : attrs

  // Create Drawer.Content
  const contentElement = j.jsxElement(
    j.jsxOpeningElement(
      j.jsxMemberExpression(
        j.jsxIdentifier("Drawer"),
        j.jsxIdentifier("Content"),
      ),
      finalAttrs,
    ),
    j.jsxClosingElement(
      j.jsxMemberExpression(
        j.jsxIdentifier("Drawer"),
        j.jsxIdentifier("Content"),
      ),
    ),
    children,
  )

  // Wrap in Drawer.Positioner
  const positionerElement = j.jsxElement(
    j.jsxOpeningElement(
      j.jsxMemberExpression(
        j.jsxIdentifier("Drawer"),
        j.jsxIdentifier("Positioner"),
      ),
      [],
    ),
    j.jsxClosingElement(
      j.jsxMemberExpression(
        j.jsxIdentifier("Drawer"),
        j.jsxIdentifier("Positioner"),
      ),
    ),
    [j.jsxText("\n    "), contentElement, j.jsxText("\n  ")],
  )

  j(path).replaceWith(positionerElement)
}

function transformPopoverContent(j: any, path: any) {
  const attrs = path.node.openingElement.attributes || []
  const children = path.node.children || []

  // Create Popover.Content
  const contentElement = j.jsxElement(
    j.jsxOpeningElement(
      j.jsxMemberExpression(
        j.jsxIdentifier("Popover"),
        j.jsxIdentifier("Content"),
      ),
      attrs,
    ),
    j.jsxClosingElement(
